using System;
using System.Linq;
using System.Reflection;

void DumpAssembly(string name) {
    var asm = AppDomain.CurrentDomain.GetAssemblies().FirstOrDefault(a => a.GetName().Name == name);
    if (asm == null) { asm = Assembly.Load(name); }
    Console.WriteLine($"\n===== {asm.GetName().Name} v{asm.GetName().Version} =====");
    var types = asm.GetExportedTypes().OrderBy(t => t.FullName);
    foreach (var t in types) {
        var kind = t.IsInterface ? "interface" : t.IsEnum ? "enum" : t.IsAbstract ? "abstract class" : "class";
        var bases = "";
        if (t.BaseType != null && t.BaseType != typeof(object))
            bases = " : " + t.BaseType.Name;
        var ifaces = t.GetInterfaces().Where(i => i.IsPublic).Select(i => i.Name).ToArray();
        if (ifaces.Length > 0) bases += (bases == "" ? " : " : ", ") + string.Join(", ", ifaces);
        Console.WriteLine($"\n  {kind} {t.FullName}{bases}");
        // Constructors
        foreach (var c in t.GetConstructors(BindingFlags.Public | BindingFlags.Instance))
            Console.WriteLine($"    ctor({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
        // Properties
        foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
            Console.WriteLine($"    {p.PropertyType.Name} {p.Name} {{ {(p.CanRead?"get;":"")}{(p.CanWrite?" set;":"")} }}");
        // Methods (non-property, non-object)
        foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly)
            .Where(m => !m.IsSpecialName))
            Console.WriteLine($"    {(m.IsStatic?"static ":"")}{m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    }
}

// Force load
